@dataclass
class DocumentChunk:
    id: str
    source: str
    chunk_index: int
    text: str
    metadata: Dict[str, Any]


class FileLock:
    def __init__(self, path: str, timeout: float = 30.0, poll: float = 0.1):
        self.path = path
        self.timeout = timeout
        self.poll = poll
        self.fd = None

    def __enter__(self):
        start = time.time()
        while True:
            try:
                self.fd = os.open(self.path, os.O_CREAT | os.O_EXCL | os.O_RDWR)
                os.write(self.fd, str(os.getpid()).encode("utf-8"))
                return self
            except FileExistsError:
                if time.time() - start > self.timeout:
                    raise TimeoutError(f"Timeout acquiring lock: {self.path}")
                time.sleep(self.poll)

    def __exit__(self, exc_type, exc, tb):
        try:
            if self.fd is not None:
                os.close(self.fd)
        finally:
            try:
                os.remove(self.path)
            except FileNotFoundError:
                pass


def sha1_text(s: str) -> str:
    return hashlib.sha1(s.encode("utf-8", errors="ignore")).hexdigest()


def read_text_file(path: str) -> str:
    with open(path, "rb") as f:
        data = f.read()
    for enc in ("utf-8", "utf-8-sig", "cp1252", "latin-1"):
        try:
            return data.decode(enc)
        except Exception:
            continue
    return data.decode("utf-8", errors="ignore")


def iter_documents_from_dir(doc_dir: str, exts: Optional[List[str]] = None) -> List[Tuple[str, str]]:
    if exts is None:
        exts = [".txt", ".md", ".markdown", ".rst", ".log", ".csv", ".json"]
    exts = [e.lower() for e in exts]
    docs = []
    for root, _, files in os.walk(doc_dir):
        for fn in files:
            path = os.path.join(root, fn)
            ext = os.path.splitext(fn)[1].lower()
            if ext not in exts:
                continue
            try:
                text = read_text_file(path)
            except Exception:
                continue
            docs.append((path, text))
    return docs


def chunk_text(text: str, chunk_size: int = 1200, chunk_overlap: int = 200) -> List[str]:
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    lines = text.split("\n")
    blocks = []
    buf = []
    buf_len = 0

    def flush():
        nonlocal buf, buf_len
        if buf:
            blocks.append("\n".join(buf).strip())
        buf = []
        buf_len = 0

    for line in lines:
        if not line and buf_len > chunk_size:
            flush()
            continue
        buf.append(line)
        buf_len += len(line) + 1
        if buf_len >= chunk_size:
            flush()

    flush()

    chunks = []
    for block in blocks:
        if not block:
            continue
        if len(block) <= chunk_size:
            chunks.append(block)
            continue
        start = 0
        while start < len(block):
            end = min(len(block), start + chunk_size)
            chunks.append(block[start:end])
            if end == len(block):
                break
            start = max(0, end - chunk_overlap)

    merged = []
    for c in chunks:
        c = c.strip()
        if c:
            merged.append(c)
    return merged


class VectorStoreFAISS:
    def __init__(self, store_dir: str, embedding_dim: int):
        self.store_dir = store_dir
        self.embedding_dim = embedding_dim
        self.index_path = os.path.join(store_dir, "index.faiss")
        self.meta_path = os.path.join(store_dir, "meta.jsonl")
        self.state_path = os.path.join(store_dir, "state.json")
        self.lock_path = os.path.join(store_dir, ".lock")

        os.makedirs(store_dir, exist_ok=True)

        self.index = None
        self.id_map: List[str] = []
        self.meta: Dict[str, Dict[str, Any]] = {}
        self._load()

    def _load(self):
        if os.path.exists(self.index_path):
            self.index = faiss.read_index(self.index_path)
        else:
            self.index = faiss.IndexFlatIP(self.embedding_dim)

        self.id_map = []
        self.meta = {}

        if os.path.exists(self.meta_path):
            with open(self.meta_path, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    obj = json.loads(line)
                    _id = obj["id"]
                    self.id_map.append(_id)
                    self.meta[_id] = obj

        if os.path.exists(self.state_path):
            try:
                with open(self.state_path, "r", encoding="utf-8") as f:
                    _ = json.load(f)
            except Exception:
                pass

        if self.index.ntotal != len(self.id_map):
            raise RuntimeError(
                f"Index/meta mismatch: index.ntotal={self.index.ntotal} meta={len(self.id_map)}. "
                f"Delete store dir '{self.store_dir}' and re-index."
            )

    def _persist(self):
        faiss.write_index(self.index, self.index_path)
        with open(self.meta_path, "w", encoding="utf-8") as f:
            for _id in self.id_map:
                f.write(json.dumps(self.meta[_id], ensure_ascii=False) + "\n")
        with open(self.state_path, "w", encoding="utf-8") as f:
            json.dump({"embedding_dim": self.embedding_dim, "count": len(self.id_map)}, f)

    def add(self, embeddings: np.ndarray, chunks: List[DocumentChunk]):
        if embeddings.dtype != np.float32:
            embeddings = embeddings.astype(np.float32)
        if embeddings.ndim != 2 or embeddings.shape[1] != self.embedding_dim:
            raise ValueError("Invalid embeddings shape")
        if len(chunks) != embeddings.shape[0]:
            raise ValueError("Chunks/embeddings count mismatch")

        with FileLock(self.lock_path):
            self._load()
            faiss.normalize_L2(embeddings)
            self.index.add(embeddings)
            for ch in chunks:
                obj = asdict(ch)
                self.id_map.append(ch.id)
                self.meta[ch.id] = obj
            self._persist()

    def search(self, query_embedding: np.ndarray, top_k: int = 8) -> List[Dict[str, Any]]:
        if query_embedding.dtype != np.float32:
            query_embedding = query_embedding.astype(np.float32)
        if query_embedding.ndim == 1:
            query_embedding = query_embedding.reshape(1, -1)
        if query_embedding.shape[1] != self.embedding_dim:
            raise ValueError("Invalid query embedding dim")

        faiss.normalize_L2(query_embedding)
        scores, idxs = self.index.search(query_embedding, top_k)
        results = []
        for score, idx in zip(scores[0].tolist(), idxs[0].tolist()):
            if idx < 0 or idx >= len(self.id_map):
                continue
            _id = self.id_map[idx]
            obj = dict(self.meta[_id])
            obj["score"] = float(score)
            results.append(obj)
        return results


class Embedder:
    def __init__(self, model_name: str = "sentence-transformers/all-MiniLM-L6-v2", device: Optional[str] = None):
        self.model = SentenceTransformer(model_name, device=device)

    @property
    def dim(self) -> int:
        return int(self.model.get_sentence_embedding_dimension())

    def embed_texts(self, texts: List[str], batch_size: int = 64) -> np.ndarray:
        emb = self.model.encode(
            texts,
            batch_size=batch_size,
            show_progress_bar=False,
            convert_to_numpy=True,
            normalize_embeddings=False,
        )
        if emb.dtype != np.float32:
            emb = emb.astype(np.float32)
        return emb

    def embed_query(self, text: str) -> np.ndarray:
        return self.embed_texts([text], batch_size=1)[0]


class RAGChatbot:
    def __init__(
        self,
        store: VectorStoreFAISS,
        embedder: Embedder,
        openai_model: str = "gpt-4.1-mini",
        api_key: Optional[str] = None,
        base_url: Optional[str] = None,
        system_prompt: Optional[str] = None,
        temperature: float = 0.2,
        max_output_tokens: int = 600,
    ):
        self.store = store
        self.embedder = embedder
        self.client = OpenAI(api_key=api_key or os.getenv("OPENAI_API_KEY"), base_url=base_url or os.getenv("OPENAI_BASE_URL"))
        self.openai_model = openai_model
        self.temperature = float(temperature)
        self.max_output_tokens = int(max_output_tokens)
        self.system_prompt = system_prompt or (
            "You are an internal knowledge base assistant for the company. "
            "Answer using ONLY the provided context. "
            "If the answer is not in the context, say you don't know and ask a clarifying question if helpful. "
            "Cite sources by file path and chunk index when relevant."
        )

    def build_prompt(self, query: str, retrieved: List[Dict[str, Any]]) -> List[Dict[str, str]]:
        context_parts = []
        for i, doc in enumerate(retrieved, start=1):
            source = doc.get("source", "")
            chunk_index = doc.get("chunk_index", -1)
            score = doc.get("score", 0.0)
            text = doc.get("text", "")
            context_parts.append(
                f"[DOC {i}] source={source} chunk={chunk_index} score={score:.4f}\n{text}"
            )
        context = "\n\n".join(context_parts) if context_parts else "(no documents retrieved)"
        user_content = (
            "CONTEXT (use all documents below as reference):\n\n"
            f"{context}\n\n"
            "USER QUESTION:\n"
            f"{query}\n\n"
            "INSTRUCTIONS:\n"
            "- Use only the context.\n"
            "- If multiple documents conflict, explain the conflict and cite both.\n"
            "- Provide a concise, accurate answer.\n"
            "- Include citations like: (source: path, chunk: N)\n"
        )
        return [
            {"role": "system", "content": self.system_prompt},
            {"role": "user", "content": user_content},
        ]

    def answer(self, query: str, top_k: int = 8) -> Dict[str, Any]:
        q_emb = self.embedder.embed_query(query)
        retrieved = self.store.search(q_emb, top_k=top_k)
        messages = self.build_prompt(query, retrieved)
        resp = self.client.chat.completions.create(
            model=self.openai_model,
            messages=messages,
            temperature=self.temperature,
            max_tokens=self.max_output_tokens,
        )
        text = resp.choices[0].message.content or ""
        return {"answer": text, "retrieved": retrieved}


def index_documents(
    doc_dir: str,
    store_dir: str,
    embed_model: str,
    device: Optional[str],
    chunk_size: int,
    chunk_overlap: int,
    batch_size: int,
    exts: Optional[List[str]] = None,
):
    embedder = Embedder(embed_model, device=device)
    store = VectorStoreFAISS(store_dir, embedding_dim=embedder.dim)

    docs = iter_documents_from_dir(doc_dir, exts=exts)
    chunks: List[DocumentChunk] = []
    texts: List[str] = []

    for path, text in docs:
        rel = os.path.relpath(path, doc_dir)
        parts = chunk_text(text, chunk_size=chunk_size, chunk_overlap=chunk_overlap)
        for i, ch in enumerate(parts):
            cid = sha1_text(rel + "\n" + str(i) + "\n" + ch)
            chunks.append(
                DocumentChunk(
                    id=cid,
                    source=rel,
                    chunk_index=i,
                    text=ch,
                    metadata={"source": rel, "chunk_index": i},
                )
            )
            texts.append(ch)

    if not chunks:
        print("No documents found to index.", file=sys.stderr)
        return

    embeddings = []
    for start in range(0, len(texts), batch_size):
        batch = texts[start : start + batch_size]
        emb = embedder.embed_texts(batch, batch_size=min(batch_size, len(batch)))
        embeddings.append(emb)
    all_emb = np.vstack(embeddings).astype(np.float32)

    store.add(all_emb, chunks)
    print(json.dumps({"indexed_chunks": len(chunks), "store_dir": store_dir, "embedding_dim": embedder.dim}))


def interactive_chat(
    store_dir: str,
    embed_model: str,
    device: Optional[str],
    openai_model: str,
    top_k: int,
    temperature: float,
    max_output_tokens: int,
    api_key: Optional[str],
    base_url: Optional[str],
):
    embedder = Embedder(embed_model, device=device)
    store = VectorStoreFAISS(store_dir, embedding_dim=embedder.dim)
    bot = RAGChatbot(
        store=store,
        embedder=embedder,
        openai_model=openai_model,
        api_key=api_key,
        base_url=base_url,
        temperature=temperature,
        max_output_tokens=max_output_tokens,
    )

    print("RAG chatbot ready. Type your question. Ctrl+C to exit.")
    while True:
        try:
            q = input("\n> ").strip()
        except (EOFError, KeyboardInterrupt):
            print("\nBye.")
            return
        if not q:
            continue
        out = bot.answer(q, top_k=top_k)
        print("\n" + out["answer"].strip() + "\n")
        print("Retrieved:")
        for d in out["retrieved"]:
            print(f"- {d.get('source')} chunk={d.get('chunk_index')} score={d.get('score'):.4f}")


def main():
    p = argparse.ArgumentParser(description="Simple Python RAG system (FAISS + SentenceTransformers + OpenAI Chat).")
    sub = p.add_subparsers(dest="cmd", required=True)

    p_index = sub.add_parser("index", help="Index documents into vector store.")
    p_index.add_argument("--doc-dir", required=True, help="Directory containing company documents.")
    p_index.add_argument("--store-dir", required=True, help="Directory to store FAISS index and metadata.")
    p_index.add_argument("--embed-model", default="sentence-transformers/all-MiniLM-L6-v2", help="SentenceTransformers model.")
    p_index.add_argument("--device", default=None, help="Embedding device (e.g., cpu, cuda).")
    p_index.add_argument("--chunk-size", type=int, default=1200)
    p_index.add_argument("--chunk-overlap", type=int, default=200)
    p_index.add_argument("--batch-size", type=int, default=64)
    p_index.add_argument("--exts", default=None, help="Comma-separated extensions to include (e.g., .txt,.md).")

    p_chat = sub.add_parser("chat", help="Interactive chat using the indexed store.")
    p_chat.add_argument("--store-dir", required=True)
    p_chat.add_argument("--embed-model", default="sentence-transformers/all-MiniLM-L6-v2")
    p_chat.add_argument("--device", default=None)
    p_chat.add_argument("--openai-model", default="gpt-4.1-mini")
    p_chat.add_argument("--top-k", type=int, default=8)
    p_chat.add_argument("--temperature", type=float, default=0.2)
    p_chat.add_argument("--max-output-tokens", type=int, default=600)
    p_chat.add_argument("--api-key", default=None)
    p_chat.add_argument("--base-url", default=None)

    args = p.parse_args()

    if args.cmd == "index":
        exts = None
        if args.exts:
            exts = [e.strip() for e in args.exts.split(",") if e.strip()]
        index_documents(
            doc_dir=args.doc_dir,
            store_dir=args.store_dir,
            embed_model=args.embed_model,
            device=args.device,
            chunk_size=args.chunk_size,
            chunk_overlap=args.chunk_overlap,
            batch_size=args.batch_size,
            exts=exts,
        )
    elif args.cmd == "chat":
        interactive_chat(
            store_dir=args.store_dir,
            embed_model=args.embed_model,
            device=args.device,
            openai_model=args.openai_model,
            top_k=args.top_k,
            temperature=args.temperature,
            max_output_tokens=args.max_output_tokens,
            api_key=args.api_key,
            base_url=args.base_url,
        )
    else:
        raise SystemExit(2)


if __name__ == "__main__":
    main()